section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/prompt-patterns-for-common-dev-tasks.json",
  "type": "object",
  "title": "Prompt Patterns for Common Dev Tasks",
  "required": [
    "prompt_id",
    "pattern",
    "intent",
    "inputs",
    "format",
    "success_criterion",
    "score"
  ],
  "additionalProperties": false,
  "properties": {
    "prompt_id": {
      "type": "string",
      "minLength": 1,
      "description": "Stable id (timestamp+author)."
    },
    "pattern": {
      "type": "string",
      "enum": [
        "Refactor",
        "Explain-Diff",
        "Bug-Repro",
        "Spec-to-Test",
        "Doc-from-Code",
        "Reverse-Stack-Trace"
      ],
      "description": "Named pattern."
    },
    "intent": {
      "type": "string",
      "minLength": 1,
      "description": "One-sentence intent."
    },
    "inputs": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Paths/snippets/URLs."
    },
    "format": {
      "type": "string",
      "minLength": 1,
      "description": "Expected output shape."
    },
    "success_criterion": {
      "type": "string",
      "minLength": 1,
      "description": "Binary check."
    },
    "score": {
      "type": "integer",
      "description": "0-3 rubric score."
    }
  }
}
